"use client";

import { useState } from "react";

/* ── Components ────────────────────────────────── */
interface Result {
  transcript: string;
  summary: string;
  timestamps: string[];
}

type Tab = "summary" | "timestamps" | "transcript";

const TABS: { id: Tab; label: string; icon: React.ReactNode }[] = [
  {
    id: "summary",
    label: "Summary",
    icon: (
      <svg
        width="14"
        height="14"
        viewBox="0 0 24 24"
        fill="none"
        stroke="currentColor"
        strokeWidth="2"
        strokeLinecap="round"
        strokeLinejoin="round"
      >
        <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z" />
        <polyline points="14 2 14 8 20 8" />
        <line x1="16" y1="13" x2="8" y2="13" />
        <line x1="16" y1="17" x2="8" y2="17" />
        <line x1="10" y1="9" x2="8" y2="9" />
      </svg>
    ),
  },
  {
    id: "timestamps",
    label: "Timestamps",
    icon: (
      <svg
        width="14"
        height="14"
        viewBox="0 0 24 24"
        fill="none"
        stroke="currentColor"
        strokeWidth="2"
        strokeLinecap="round"
        strokeLinejoin="round"
      >
        <circle cx="12" cy="12" r="10" />
        <polyline points="12 6 12 12 16 14" />
      </svg>
    ),
  },
  {
    id: "transcript",
    label: "Transcript",
    icon: (
      <svg
        width="14"
        height="14"
        viewBox="0 0 24 24"
        fill="none"
        stroke="currentColor"
        strokeWidth="2"
        strokeLinecap="round"
        strokeLinejoin="round"
      >
        <line x1="8" y1="6" x2="21" y2="6" />
        <line x1="8" y1="12" x2="21" y2="12" />
        <line x1="8" y1="18" x2="21" y2="18" />
        <line x1="3" y1="6" x2="3.01" y2="6" />
        <line x1="3" y1="12" x2="3.01" y2="12" />
        <line x1="3" y1="18" x2="3.01" y2="18" />
      </svg>
    ),
  },
];

/* ── Sub-components ───────────────────────────── */

// UrlInput
function UrlInput({
  url,
  setUrl,
  onSubmit,
  loading,
}: {
  url: string;
  setUrl: (url: string) => void;
  onSubmit: (url: string) => void;
  loading: boolean;
}) {
  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!loading && url.trim()) onSubmit(url.trim());
  };

  return (
    <form className="flex w-full gap-2" onSubmit={handleSubmit}>
      <input
        type="url"
        value={url}
        placeholder="Paste YouTube link..."
        onChange={(e) => setUrl(e.target.value)}
        className="flex-1 rounded-lg border border-gray-700 bg-gray-900 px-4 py-2 text-white placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-red-500"
        required
      />
      <button
        type="submit"
        disabled={loading}
        className="rounded-lg bg-red-600 px-4 py-2 text-white transition hover:bg-red-700 disabled:opacity-50"
      >
        Summarize
      </button>
    </form>
  );
}

// Loader
function Loader() {
  return (
    <div className="flex justify-center py-6">
      <div className="h-8 w-8 animate-spin rounded-full border-4 border-t-red-500 border-gray-700"></div>
    </div>
  );
}

// SummaryBox
function SummaryBox({ summary }: { summary: string }) {
  return <div className="whitespace-pre-wrap text-gray-200">{summary}</div>;
}

// TranscriptBox
function TranscriptBox({ transcript }: { transcript: string }) {
  return <div className="whitespace-pre-wrap text-gray-300">{transcript}</div>;
}

// TimestampSummary
function TimestampSummary({ timestamps }: { timestamps: string[] }) {
  return (
    <ul className="list-disc pl-5 text-gray-300">
      {timestamps.map((t, i) => (
        <li key={i}>{t}</li>
      ))}
    </ul>
  );
}

/* ── Page ─────────────────────────────────────── */
export default function HomePage() {
  const [url, setUrl] = useState("");
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<Result | null>(null);
  const [apiError, setApiError] = useState("");
  const [activeTab, setActiveTab] = useState<Tab>("summary");

  const handleSummarize = async (submittedUrl: string) => {
    setApiError("");
    setResult(null);
    setLoading(true);

    try {
      const res = await fetch("/api/summarize", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ url: submittedUrl }),
      });

      const data = await res.json();
      if (!res.ok) throw new Error(data?.error || "Server error");

      setResult(data);
      setActiveTab("summary");
      setUrl(""); // ✅ Clear input
    } catch (err: unknown) {
      setApiError(err instanceof Error ? err.message : "Unexpected error");
    } finally {
      setLoading(false);
    }
  };

  const handleReset = () => {
    setResult(null);
    setApiError("");
    setUrl("");
  };

  return (
    <div className="relative flex min-h-screen flex-col bg-gray-900 text-white">
      <main className="relative z-10 mx-auto w-full max-w-2xl flex-col px-4 py-16 md:py-24 flex-1">
        {/* Header */}
        <header className="mb-10 text-center">
          <h1 className="mb-2 text-4xl font-bold md:text-5xl">YouTube Summarizer</h1>
          <p className="mx-auto max-w-sm text-sm md:text-base text-gray-300">
            Paste a link and get AI-powered summary, timestamps, and transcript.
          </p>
        </header>

        {/* Input */}
        <section className="card mb-4 p-5 bg-gray-800 rounded-xl border border-gray-700">
          <UrlInput url={url} setUrl={setUrl} onSubmit={handleSummarize} loading={loading} />
        </section>

        {/* Loader */}
        {loading && <Loader />}

        {/* Error */}
        {apiError && !loading && (
          <div className="mb-4 rounded-xl border border-red-500 bg-red-900/20 px-5 py-4 text-red-400">
            <p className="font-semibold">Something went wrong</p>
            <p className="mt-1">{apiError}</p>
          </div>
        )}

        {/* Results */}
        {result && !loading && (
          <div className="flex flex-col gap-4">
            {/* Tabs */}
            <div className="flex gap-1 rounded-xl bg-gray-800 p-1.5 border border-gray-700" role="tablist">
              {TABS.map((tab) => (
                <button
                  key={tab.id}
                  role="tab"
                  aria-selected={activeTab === tab.id}
                  onClick={() => setActiveTab(tab.id)}
                  className={`flex-1 flex justify-center gap-1 rounded-lg px-2 py-1 text-sm transition-colors ${
                    activeTab === tab.id ? "bg-red-600 text-white" : "text-gray-300 hover:bg-gray-700"
                  }`}
                >
                  {tab.icon}
                  <span className="hidden sm:inline">{tab.label}</span>
                </button>
              ))}
            </div>

            {/* Content */}
            <div className="card p-5 md:p-6 bg-gray-800 rounded-xl border border-gray-700">
              {activeTab === "summary" && <SummaryBox summary={result.summary} />}
              {activeTab === "timestamps" && <TimestampSummary timestamps={result.timestamps} />}
              {activeTab === "transcript" && <TranscriptBox transcript={result.transcript} />}
            </div>

            {/* Reset */}
            <div className="text-center mt-4">
              <button
                onClick={handleReset}
                className="text-sm text-gray-400 hover:text-gray-200 transition"
              >
                ↺ Summarize another video
              </button>
            </div>
          </div>
        )}
      </main>

      <footer className="text-center text-xs pb-8 text-gray-500">
        Powered by OpenAI Whisper · HuggingFace · yt-dlp · Next.js 14
      </footer>
    </div>
  );
}
